        for u, v, edge_data in graph_copy.out_edges(control_domain_node, data=True):
            if edge_data.get('type') == 'RK_CONTAINS':
                children.append(v)
    capacity_list = []
    for child in children:
        queue = [child]
        visited = set([child])
        total_capacity = 0
        while queue:
            current = queue.pop(0)
            node_attrs = graph_copy.nodes[current]
            if 'EK_PORT' in node_attrs['type']:
                total_capacity += node_attrs['physical_capacity_bps']
            for neighbor in graph_copy.successors(current):
                edge_data = graph_copy[current][neighbor]
