                    visited.add(neighbor)
                    queue.append(neighbor)
        child_name = graph_copy.nodes[child]['name']
        capacity_list.append((child_name, total_capacity))
    capacity_list.sort(key=lambda x: x[1], reverse=True)
    updated_graph_data = nx.readwrite.json_graph.node_link_data(graph_copy)
    return {
        'type': 'list',
        'data': capacity_list,
        'updated_graph': updated_graph_data
    }

